use cardano/transaction.{Transaction, OutputReference, Input, Output, InlineDatum, find_input}
use cardano/assets
use aiken/collection/list

type OracleDatum {
  ada_usd_price_num: Int,
  ada_usd_price_den: Int,
}

type SaleDatum {
  seller: ByteArray,
  usd_cost_cents: Int,
  oracle_ref: OutputReference,
  oracle_nft_policy: ByteArray,
}

validator oracle_payment {
  spend(datum: Option<SaleDatum>, _redeemer: Data, _own_ref: OutputReference, self: Transaction) -> Bool {
    expect Some(sale) = datum
    expect Some(ref_in) = transaction.find_input(self.reference_inputs, sale.oracle_ref)
    expect True = assets.has_any_nft(ref_in.output.value, sale.oracle_nft_policy)
    expect InlineDatum(raw) = ref_in.output.datum
    expect oracle_data: OracleDatum = raw
    let required_lovelace =
      sale.usd_cost_cents * oracle_data.ada_usd_price_den * 10000 / oracle_data.ada_usd_price_num
    let paid_to_seller =
      list.foldl(
        self.outputs,
        0,
        fn(output, acc) {
          if output.address.payment_credential == cardano/address.from_verification_key(sale.seller).payment_credential {
            acc + assets.lovelace_of(output.value)
          } else {
            acc
          }
        },
      )
    paid_to_seller >= required_lovelace
  }
}

