  offered_asset: ByteArray,
  offered_amount: Int,
  wanted_policy: ByteArray,
  wanted_asset: ByteArray,
  oracle_ref: OutputReference,
  oracle_nft: ByteArray,
}

validator fair_swap {
  spend(datum: Option<SwapDatum>, _redeemer: Data, own_ref: OutputReference, self: Transaction) -> Bool {
    expect Some(swap) = datum
    expect Some(ref_in) = transaction.find_input(self.reference_inputs, swap.oracle_ref)
    expect True = assets.has_any_nft(ref_in.output.value, swap.oracle_nft)
    expect InlineDatum(raw) = ref_in.output.datum
    expect rate: RateDatum = raw
    let fair_amount = swap.offered_amount * rate.rate_num / rate.rate_den
    let min_acceptable = fair_amount * 99 / 100
    let received =
      list.foldl(
        self.outputs,
        0,
        fn(output, acc) {
          if output.address == cardano/address.from_verification_key(swap.owner) {
            acc + assets.quantity_of(output.value, swap.wanted_policy, swap.wanted_asset)
          } else {
            acc
          }
        },
      )
    received >= min_acceptable
  }
}

