use cardano/transaction.{Transaction, OutputReference, InlineDatum, find_input}
use cardano/assets

type OracleDatum {
  ada_price_num: Int,
  ada_price_den: Int,
}

type LoanDatum {
  borrower: ByteArray,
  loan_amount_cents: Int,
  collateral_lovelace: Int,
  min_collateral_ratio_pct: Int,
  oracle_ref: OutputReference,
  oracle_nft_policy: ByteArray,
}

type LoanAction {
  Liquidate
  Repay
}

validator lending_protocol {
  spend(datum: Option<LoanDatum>, redeemer: LoanAction, _own_ref: OutputReference, self: Transaction) -> Bool {
    expect Some(loan) = datum
    expect Some(ref_in) = transaction.find_input(self.reference_inputs, loan.oracle_ref)
    expect True = assets.has_any_nft(ref_in.output.value, loan.oracle_nft_policy)
    expect InlineDatum(raw) = ref_in.output.datum
    expect oracle: OracleDatum = raw
    let collateral_value_cents =
      loan.collateral_lovelace * oracle.ada_price_num / ( oracle.ada_price_den * 10000 )
    let current_ratio_pct =
      collateral_value_cents * 100 / loan.loan_amount_cents
    when redeemer is {
      Liquidate -> {
        let is_undercollateralized = current_ratio_pct < loan.min_collateral_ratio_pct
        is_undercollateralized
      }
      Repay -> {
        let signed_by_borrower =
          list.has(self.extra_signatories, loan.borrower)
        signed_by_borrower
      }
    }
  }
}

