type ConfigDatum {
  fee_rate_bps: Int,
  fee_collector: ByteArray,
}

type SpendDatum {
  owner: ByteArray,
  config_ref: OutputReference,
}

type SpendRedeemer {
  Withdraw
}

validator fee_protocol {
  spend(datum: Option<SpendDatum>, redeemer: SpendRedeemer, own_ref: OutputReference, self: Transaction) -> Bool {
    expect Some(d) = datum
    let SpendDatum { owner, config_ref } = d
    expect Some(config_input) = find_input(self.reference_inputs, config_ref)
    expect InlineDatum(raw_config) = config_input.output.datum
    expect config: ConfigDatum = raw_config
    expect Some(own_input) = find_input(self.inputs, own_ref)
    let withdraw_amount = assets.lovelace_of(own_input.output.value)
    let fee_amount = withdraw_amount * config.fee_rate_bps / 10000
    let fee_paid =
      list.any(
        self.outputs,
        fn(o) {
          when o.address.payment_credential is {
            cardano/address.VerificationKey(hash) ->
              hash == config.fee_collector && assets.lovelace_of(o.value) >= fee_amount
            _ -> False
          }
        },
      )
    let signed = list.has(self.extra_signatories, owner)
    signed && fee_paid && fee_amount > 0
  }
}

