use cardano/transaction.{Transaction, OutputReference, InlineDatum, find_input, find_script_outputs}
use cardano/assets
use aiken/collection/list
use cardano/address.{VerificationKey}

type ProtocolConfig {
  max_supply: Int,
  fee_rate_bps: Int,
  admin_key: ByteArray,
  fee_collector: ByteArray,
  token_policy: ByteArray,
  token_name: ByteArray,
}

type ProtocolDatum {
  current_supply: Int,
  config_ref: OutputReference,
  script_hash: ByteArray,
}

type ProtocolAction {
  MintTokens { amount: Int }
  UpdateState
}

validator protocol_params {
  spend(datum: Option<ProtocolDatum>, redeemer: ProtocolAction, own_ref: OutputReference, self: Transaction) -> Bool {
    expect Some(d) = datum
    expect Some(config_in) = find_input(self.reference_inputs, d.config_ref)
    expect InlineDatum(raw) = config_in.output.datum
    expect config: ProtocolConfig = raw
    let admin_signed = list.has(self.extra_signatories, config.admin_key)
    when redeemer is {
      MintTokens(amount) -> {
        let new_supply = d.current_supply + amount
        let within_max = new_supply <= config.max_supply
        let fee = amount * config.fee_rate_bps / 10000
        let fee_paid =
          list.any(
            self.outputs,
            fn(o) {
              when o.address.payment_credential is {
                VerificationKey(h) ->
                  h == config.fee_collector && assets.lovelace_of(o.value) >= fee
                _ -> False
              }
            },
          )
        let continuing_outputs = find_script_outputs(self.outputs, d.script_hash)
        let state_updated =
          list.any(
            continuing_outputs,
            fn(o) {
              expect InlineDatum(out_raw) = o.datum
              expect out_d: ProtocolDatum = out_raw
              out_d.current_supply == new_supply && out_d.config_ref == d.config_ref
            },
          )
        admin_signed && within_max && fee_paid && state_updated
      }
      UpdateState -> admin_signed
    }
  }
}

