type ConfigProtocolo {
  suministro_maximo: Int,
  tasa_comision_bps: Int,
  clave_admin: ByteArray,
  colector_comision: ByteArray,
  politica_token: ByteArray,
  nombre_token: ByteArray,
}

type DatumProtocolo {
  suministro_actual: Int,
  ref_config: OutputReference,
  hash_script: ByteArray,
}

type AccionProtocolo {
  Emitir { cantidad: Int }
  ActualizarEstado
}

validator parametros_protocolo {
  spend(datum: Option<DatumProtocolo>, redeemer: AccionProtocolo, own_ref: OutputReference, self: Transaction) -> Bool {
    expect Some(d) = datum
    expect Some(entrada_cfg) = find_input(self.reference_inputs, d.ref_config)
    expect InlineDatum(raw) = entrada_cfg.output.datum
    expect cfg: ConfigProtocolo = raw
    let admin_firmo = list.has(self.extra_signatories, cfg.clave_admin)
    when redeemer is {
      Emitir(cantidad) -> {
        let nuevo_suministro = d.suministro_actual + cantidad
        let dentro_limite = nuevo_suministro <= cfg.suministro_maximo
        let comision = cantidad * cfg.tasa_comision_bps / 10000
        let comision_pagada =
          list.any(
            self.outputs,
            fn(o) {
              when o.address.payment_credential is {
                VerificationKey(h) ->
                  h == cfg.colector_comision && assets.lovelace_of(o.value) >= comision
                _ -> False
              }
            },
          )
        let salidas_cont = find_script_outputs(self.outputs, d.hash_script)
        let estado_ok =
          list.any(
            salidas_cont,
            fn(o) {
              expect InlineDatum(r) = o.datum
              expect sd: DatumProtocolo = r
              sd.suministro_actual == nuevo_suministro && sd.ref_config == d.ref_config
            },
          )
        admin_firmo && dentro_limite && comision_pagada && estado_ok
      }
      ActualizarEstado -> admin_firmo
    }
  }
}

