fn count_approved_signers(
  signatories: List<ByteArray>,
  approved: List<ByteArray>,
) -> Int {
  list.foldl(
    signatories,
    0,
    fn(signer, acc) {
      if list.has(approved, signer) {
        acc + 1
      } else {
        acc
      }
    },
  )
}

validator dao_treasury {
  spend(
    _datum: Option<Data>,
    redeemer: TreasuryRedeemer,
    _own_ref: OutputReference,
