    expect Some(ref_in) =
      transaction.find_input(self.reference_inputs, redeemer.multisig_ref)
    expect InlineDatum(raw) = ref_in.output.datum
    expect ms_data: MultisigDatum = raw
    let approved = ms_data.approved_signers
    let sig_count =
      count_approved_signers(self.extra_signatories, approved)
    sig_count >= required_sigs
  }
}

