  pool_script_hash: ByteArray,
}

validator constant_product_swap {
  spend(datum: Option<SwapDatum>, _redeemer: Data, own_ref: OutputReference, self: Transaction) -> Bool {
    expect Some(swap_data) = datum
    expect Some(pool_ref_input) = find_input(self.reference_inputs, swap_data.pool_ref)
    expect InlineDatum(raw_reserves) = pool_ref_input.output.datum
    expect old_reserves: PoolReserves = raw_reserves
    let old_k = old_reserves.reserve_a * old_reserves.reserve_b
    let pool_outputs =
      list.filter(
        self.outputs,
        fn(o) {
          when o.address.payment_credential is {
            cardano/address.Script(h) -> h == swap_data.pool_script_hash
            _ -> False
          }
        },
      )
    expect [pool_output, ..] = pool_outputs
    let new_reserve_a = assets.quantity_of(pool_output.value, old_reserves.token_a_policy, old_reserves.token_a_name)
    let new_reserve_b = assets.quantity_of(pool_output.value, old_reserves.token_b_policy, old_reserves.token_b_name)
    let new_k = new_reserve_a * new_reserve_b
    new_k >= old_k
  }
}

