  reward_name: AssetName,
}

type FarmDatum {
  staker: ByteArray,
  staked_amount: Int,
  last_claim_epoch: Int,
  reward_rate_ref: OutputReference,
  rate_nft_policy: PolicyId,
}

type FarmRedeemer {
  ClaimReward
  Withdraw
}

validator yield_farm {
  spend(datum: Option<FarmDatum>, redeemer: FarmRedeemer, own_ref: OutputReference, self: Transaction) -> Bool {
    expect Some(farm) = datum
    when redeemer is {
      Withdraw -> list.has(self.extra_signatories, farm.staker)
      ClaimReward -> {
        expect list.has(self.extra_signatories, farm.staker)
        expect Some(rate_input) = find_input(self.reference_inputs, farm.reward_rate_ref)
        expect assets.has_any_nft(rate_input.output.value, farm.rate_nft_policy)
        expect InlineDatum(raw_rate) = rate_input.output.datum
        expect rate_data: RewardRateData = raw_rate
        expect rate_data.current_epoch > farm.last_claim_epoch
        let epochs_elapsed = rate_data.current_epoch - farm.last_claim_epoch
        let user_share = farm.staked_amount * rate_data.reward_per_epoch / rate_data.total_staked
        let expected_reward = user_share * epochs_elapsed
        let staker_receives_reward =
          list.any(
            self.outputs,
            fn(o) {
              assets.quantity_of(o.value, rate_data.reward_policy, rate_data.reward_name) >= expected_reward
            },
          )
        staker_receives_reward
      }
