use cardano/transaction.{Transaction, OutputReference, Input, find_input, InlineDatum}
use cardano/assets.{PolicyId, AssetName}
use aiken/collection/list

type InterestRateOracle {
  annual_rate_bps: Int,
  last_updated_slot: Int,
}

type LoanDatum {
  borrower: ByteArray,
  principal: Int,
  loan_start_slot: Int,
  loan_policy: PolicyId,
  loan_name: AssetName,
  oracle_ref: OutputReference,
  oracle_nft_policy: PolicyId,
}

type LoanRedeemer {
  Repay
  Liquidate
}

validator lending_market {
  spend(datum: Option<LoanDatum>, redeemer: LoanRedeemer, own_ref: OutputReference, self: Transaction) -> Bool {
    expect Some(loan) = datum
    expect Some(oracle_input) = find_input(self.reference_inputs, loan.oracle_ref)
    expect assets.has_any_nft(oracle_input.output.value, loan.oracle_nft_policy)
    expect InlineDatum(raw_oracle) = oracle_input.output.datum
    expect rate_oracle: InterestRateOracle = raw_oracle
    let slots_elapsed = rate_oracle.last_updated_slot - loan.loan_start_slot
    let slots_per_year = 31_536_000_000
    let accrued_interest = loan.principal * rate_oracle.annual_rate_bps * slots_elapsed / (10_000 * slots_per_year)
    let total_owed = loan.principal + accrued_interest
    when redeemer is {
      Repay -> {
        expect list.has(self.extra_signatories, loan.borrower)
        let repayment_made =
          list.any(
            self.outputs,
            fn(o) {
              assets.quantity_of(o.value, loan.loan_policy, loan.loan_name) >= total_owed
            },
          )
        repayment_made
      }
      Liquidate -> {
        let slots_overdue_threshold = 2_592_000_000
        let is_overdue = slots_elapsed > slots_overdue_threshold
        is_overdue
      }
    }
  }
}

use cardano/transaction.{Transaction, OutputReference, Input, find_input, InlineDatum}
use cardano/assets.{PolicyId, AssetName}
use aiken/collection/list
use aiken/collection/pairs

type CIP68Metadata {
  name: ByteArray,
  image: ByteArray,
  version: Int,
}

type MetadataRequirement {
  required_version: Int,
  required_policy: PolicyId,
  reference_nft_ref: OutputReference,
  user_nft_name: AssetName,
}

validator cip68_metadata_check {
  spend(
    _datum: Option<Data>,
    redeemer: MetadataRequirement,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    let MetadataRequirement {
      required_version,
      required_policy,
      reference_nft_ref,
      user_nft_name,
    } = redeemer

    // Read CIP-68 reference NFT from reference inputs
    expect Some(ref_input) =
      transaction.find_input(self.reference_inputs, reference_nft_ref)

    // Extract metadata from the inline datum of the reference NFT
    expect InlineDatum(raw_metadata) = ref_input.output.datum
    expect metadata: CIP68Metadata = raw_metadata

    // Validate the reference NFT is from the correct policy
    let ref_value = ref_input.output.value
    let has_ref_nft = assets.has_any_nft(ref_value, required_policy)

    // Validate metadata meets the version requirement
    let version_ok = metadata.version >= required_version

    // Validate that the name field is not empty
    let name_ok = metadata.name != ""

    // Validate that the image field is not empty
    let image_ok = metadata.image != ""

    // Ensure the spender holds the corresponding user NFT (CIP-68 user token)
    let user_holds_nft =
      list.any(
        self.inputs,
        fn(input) {
          assets.quantity_of(input.output.value, required_policy, user_nft_name) >= 1
        },
      )

    has_ref_nft && version_ok && name_ok && image_ok && user_holds_nft
  }
}

use cardano/transaction.{Transaction, OutputReference, Input, find_input, InlineDatum}
use cardano/assets.{PolicyId, AssetName}
use aiken/collection/list

type MetadatosCIP68 {
