}

type RequisitosMetadatos {
  version_minima: Int,
  politica_requerida: PolicyId,
  ref_nft_referencia: OutputReference,
  nombre_nft_usuario: AssetName,
}

validator verificar_metadatos_cip68 {
  spend(
    _datum: Option<Data>,
    redeemer: RequisitosMetadatos,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    let RequisitosMetadatos {
      version_minima,
      politica_requerida,
      ref_nft_referencia,
      nombre_nft_usuario,
    } = redeemer

    // Leer el NFT de referencia CIP-68 desde las entradas de referencia
    expect Some(entrada_ref) =
      transaction.find_input(self.reference_inputs, ref_nft_referencia)

    // Extraer metadatos del datum en línea
    expect InlineDatum(datos_crudos) = entrada_ref.output.datum
    expect metadatos: MetadatosCIP68 = datos_crudos

    // Verificar que el NFT de referencia tiene la política correcta
    let tiene_nft_ref = assets.has_any_nft(entrada_ref.output.value, politica_requerida)

    // Verificar versión mínima
    let version_valida = metadatos.version >= version_minima

    // Verificar que nombre no esté vacío
    let nombre_valido = metadatos.nombre != ""

    // Verificar que imagen no esté vacía
    let imagen_valida = metadatos.imagen != ""

    // Verificar que descripción no esté vacía
    let descripcion_valida = metadatos.descripcion != ""

    // Verificar que el usuario posee el token NFT correspondiente
    let usuario_tiene_nft =
      list.any(
        self.inputs,
        fn(input) {
          assets.quantity_of(input.output.value, politica_requerida, nombre_nft_usuario) >= 1
        },
      )

    tiene_nft_ref && version_valida && nombre_valido && imagen_valida && descripcion_valida && usuario_tiene_nft
  }
}

use cardano/transaction.{Transaction, OutputReference, Input, find_input, InlineDatum}
use cardano/assets.{PolicyId, AssetName, Value}
use aiken/collection/list
use aiken/collection/pairs

type CollectionConfig {
  collection_policy: PolicyId,
  max_supply: Int,
  prefix: ByteArray,
}

type CollectionRedeemer {
  config_ref: OutputReference,
  minted_asset_name: AssetName,
}

validator collection_membership {
  spend(
    _datum: Option<Data>,
    redeemer: CollectionRedeemer,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    let CollectionRedeemer { config_ref, minted_asset_name } = redeemer

    // Read collection configuration from reference input
    expect Some(config_input) =
      transaction.find_input(self.reference_inputs, config_ref)

    expect InlineDatum(raw_config) = config_input.output.datum
    expect config: CollectionConfig = raw_config

    let CollectionConfig { collection_policy, max_supply, prefix } = config

    // Check that something is being minted under the collection policy
    let minted = self.mint
    let minted_quantity =
      assets.quantity_of(minted, collection_policy, minted_asset_name)

    // Must mint exactly 1 NFT
    let is_single_mint = minted_quantity == 1

    // Validate asset name starts with the collection prefix
    let prefix_len = builtin.length_of_bytearray(prefix)
    let name_prefix = builtin.slice_bytearray(0, prefix_len, minted_asset_name)
    let has_valid_prefix = name_prefix == prefix

    // Count total tokens of this policy already in inputs (existing supply proxy)
    let existing_count =
      list.foldl(
        self.inputs,
        0,
        fn(input, acc) {
          let tokens = assets.tokens(input.output.value, collection_policy)
          acc + list.length(pairs.keys(tokens))
        },
      )

    // Ensure we don't exceed max supply
    let within_supply = existing_count + 1 <= max_supply

    is_single_mint && has_valid_prefix && within_supply
  }
}

use cardano/transaction.{Transaction, OutputReference, Input, find_input, InlineDatum}
use cardano/assets.{PolicyId, AssetName}
use aiken/collection/list
use aiken/collection/pairs

type ConfiguracionColeccion {
  politica_coleccion: PolicyId,
  suministro_maximo: Int,
  prefijo_nombre: ByteArray,
}

type RedeemerColeccion {
  ref_configuracion: OutputReference,
  nombre_token_acunado: AssetName,
}

validator membresia_coleccion {
  spend(
    _datum: Option<Data>,
    redeemer: RedeemerColeccion,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    let RedeemerColeccion { ref_configuracion, nombre_token_acunado } =
      redeemer

    // Leer configuración de la colección desde entrada de referencia
    expect Some(entrada_config) =
      transaction.find_input(self.reference_inputs, ref_configuracion)

    expect InlineDatum(datos_config) = entrada_config.output.datum
    expect config: ConfiguracionColeccion = datos_config

    let ConfiguracionColeccion {
      politica_coleccion,
      suministro_maximo,
      prefijo_nombre,
    } = config

    // Verificar que se está acuñando bajo la política de la colección
    let cantidad_acunada =
      assets.quantity_of(self.mint, politica_coleccion, nombre_token_acunado)

    // Debe acuñar exactamente 1 NFT
    let es_acunacion_unica = cantidad_acunada == 1

    // Verificar que el nombre empieza con el prefijo de la colección
    let longitud_prefijo = builtin.length_of_bytearray(prefijo_nombre)
    let prefijo_actual =
      builtin.slice_bytearray(0, longitud_prefijo, nombre_token_acunado)
    let prefijo_valido = prefijo_actual == prefijo_nombre

    // Contar tokens existentes de esta política en las entradas
    let conteo_existente =
      list.foldl(
        self.inputs,
        0,
        fn(input, acc) {
          let tokens = assets.tokens(input.output.value, politica_coleccion)
          acc + list.length(pairs.keys(tokens))
        },
      )

    // No exceder suministro máximo
    let dentro_del_limite = conteo_existente + 1 <= suministro_maximo

    es_acunacion_unica && prefijo_valido && dentro_del_limite
  }
}

use cardano/transaction.{Transaction, OutputReference, Output, Input, find_input, InlineDatum}
use cardano/assets.{PolicyId, AssetName, Lovelace}
use cardano/address.{Address, Credential, VerificationKey}
use aiken/collection/list

type RoyaltyInfo {
  royalty_rate_bps: Int,
  royalty_recipient: Address,
  collection_policy: PolicyId,
}

type ListingDatum {
  seller: Address,
  price_lovelace: Int,
  nft_policy: PolicyId,
  nft_name: AssetName,
}

type MarketplaceRedeemer {
  royalty_ref: OutputReference,
}

validator nft_marketplace_royalty {
  spend(
    datum: Option<ListingDatum>,
    redeemer: MarketplaceRedeemer,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(listing) = datum

    let ListingDatum { seller, price_lovelace, nft_policy, nft_name } = listing
    let MarketplaceRedeemer { royalty_ref } = redeemer

    // Read royalty configuration from reference input
    expect Some(royalty_input) =
      transaction.find_input(self.reference_inputs, royalty_ref)

    expect InlineDatum(raw_royalty) = royalty_input.output.datum
    expect royalty_info: RoyaltyInfo = raw_royalty

    let RoyaltyInfo { royalty_rate_bps, royalty_recipient, collection_policy } =
      royalty_info

    // Validate the royalty info is from the correct collection
    let royalty_from_collection =
      assets.has_any_nft(royalty_input.output.value, collection_policy)

    // The NFT must be from the same collection
    let nft_matches_collection = nft_policy == collection_policy

    // Calculate royalty amount: (price * rate_bps) / 10000
    let royalty_amount = price_lovelace * royalty_rate_bps / 10000
    let seller_amount = price_lovelace - royalty_amount

    // Check that an output pays the royalty recipient
    let royalty_paid =
      list.any(
        self.outputs,
        fn(output) {
          output.address == royalty_recipient && assets.lovelace_of(
            output.value,
          ) >= royalty_amount
        },
      )

    // Check that an output pays the seller
    let seller_paid =
      list.any(
        self.outputs,
        fn(output) {
          output.address == seller && assets.lovelace_of(output.value) >= seller_amount
        },
      )

    // Check the NFT is being transferred (present in outputs)
    let nft_transferred =
      list.any(
        self.outputs,
        fn(output) {
          assets.quantity_of(output.value, nft_policy, nft_name) == 1
        },
      )

    royalty_from_collection && nft_matches_collection && royalty_paid && seller_paid && nft_transferred
  }
}

