}

validator marketplace_con_regalias {
  spend(
    datum: Option<DatumListado>,
    redeemer: RedeemerMarketplace,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(listado) = datum

    let DatumListado { vendedor, precio_lovelace, politica_nft, nombre_nft } =
      listado
    let RedeemerMarketplace { ref_regalias } = redeemer

    // Leer configuración de regalías desde entrada de referencia
    expect Some(entrada_regalias) =
      transaction.find_input(self.reference_inputs, ref_regalias)

    expect InlineDatum(datos_regalias) = entrada_regalias.output.datum
    expect info_regalias: InfoRegalias = datos_regalias

