    let regalias_de_coleccion =
      assets.has_any_nft(entrada_regalias.output.value, politica_coleccion)

    // El NFT debe ser de la misma colección
    let nft_coincide = politica_nft == politica_coleccion

    // Calcular monto de regalía: (precio * tasa_bps) / 10000
    let monto_regalia = precio_lovelace * tasa_regalias_bps / 10000
    let monto_vendedor = precio_lovelace - monto_regalia

