    // Verificar que el NFT se transfiere
    let nft_transferido =
      list.any(
        self.outputs,
        fn(output) {
          assets.quantity_of(output.value, politica_nft, nombre_nft) == 1
        },
      )

    regalias_de_coleccion && nft_coincide && regalia_pagada && vendedor_pagado && nft_transferido
  }
