use cardano/transaction.{Transaction, OutputReference, Input, find_input, InlineDatum}
use cardano/assets
use aiken/collection/list

pub type MachineState {
  Idle
  Processing
  Completed
  Failed
}

pub type TransitionAction {
  Start
  Finish
  Error
  Reset
}

pub type StateDatum {
  current_state: MachineState,
  owner: ByteArray,
  nonce: Int,
}

pub type SpendRedeemer {
  action: TransitionAction,
  state_machine_ref: OutputReference,
}

fn valid_transition(from: MachineState, action: TransitionAction) -> MachineState {
  when from is {
    Idle -> when action is {
      Start -> Processing
      _ -> fail @"Invalid transition from Idle"
    }
    Processing -> when action is {
      Finish -> Completed
      Error -> Failed
      _ -> fail @"Invalid transition from Processing"
    }
    Failed -> when action is {
      Reset -> Idle
      _ -> fail @"Invalid transition from Failed"
    }
    Completed -> when action is {
      Reset -> Idle
      _ -> fail @"Invalid transition from Completed"
    }
  }
}

validator state_machine_consumer {
  spend(
    datum: Option<Data>,
    redeemer: SpendRedeemer,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    let SpendRedeemer { action, state_machine_ref } = redeemer
    expect Some(ref_input) =
      transaction.find_input(self.reference_inputs, state_machine_ref)
    expect InlineDatum(raw_state) = ref_input.output.datum
    expect state_datum: StateDatum = raw_state
    let expected_next = valid_transition(state_datum.current_state, action)
    expect Some(own_datum_raw) = datum
    expect own_state: StateDatum = own_datum_raw
    let has_owner_sig =
      list.has(self.extra_signatories, state_datum.owner)
    and {
      has_owner_sig,
      own_state.current_state == expected_next,
      own_state.nonce == state_datum.nonce + 1,
    }
  }
}

