pub type Estado {
  Inactivo
  Activo
  Pausado
  Finalizado
}

pub type Accion {
  Activar
  Pausar
  Reanudar
  Finalizar
}

pub type DatumEstado {
  estado_actual: Estado,
  administrador: ByteArray,
  version: Int,
}

pub type RedeemerTransicion {
  accion: Accion,
  referencia_maquina: OutputReference,
}

fn transicion_valida(desde: Estado, accion: Accion) -> Estado {
  when desde is {
    Inactivo -> when accion is {
      Activar -> Activo
      _ -> fail @"Transicion invalida desde Inactivo"
    }
    Activo -> when accion is {
      Pausar -> Pausado
      Finalizar -> Finalizado
      _ -> fail @"Transicion invalida desde Activo"
    }
    Pausado -> when accion is {
      Reanudar -> Activo
      Finalizar -> Finalizado
      _ -> fail @"Transicion invalida desde Pausado"
    }
    Finalizado -> fail @"No hay transiciones desde Finalizado"
  }
}

validator maquina_estados {
  spend(
    datum: Option<Data>,
    redeemer: RedeemerTransicion,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    let RedeemerTransicion { accion, referencia_maquina } = redeemer
    expect Some(ref_in) =
      transaction.find_input(self.reference_inputs, referencia_maquina)
    expect InlineDatum(raw) = ref_in.output.datum
    expect estado_ref: DatumEstado = raw
    let siguiente_estado = transicion_valida(estado_ref.estado_actual, accion)
    expect Some(datum_propio_raw) = datum
    expect datum_propio: DatumEstado = datum_propio_raw
    let firma_admin =
      list.has(self.extra_signatories, estado_ref.administrador)
    and {
      firma_admin,
      datum_propio.estado_actual == siguiente_estado,
      datum_propio.version == estado_ref.version + 1,
    }
  }
}

