use cardano/transaction.{Transaction, OutputReference, Input, find_input, InlineDatum}
use cardano/assets
use aiken/collection/list
use aiken/math

pub type Position {
  x: Int,
  y: Int,
}

pub type GameState {
  player: ByteArray,
  position: Position,
  score: Int,
  level: Int,
}

pub type MoveDirection {
  MoveUp
  MoveDown
  MoveLeft
  MoveRight
}

pub type GameRedeemer {
  game_state_ref: OutputReference,
  direction: MoveDirection,
  points_earned: Int,
}

fn apply_move(pos: Position, dir: MoveDirection) -> Position {
  when dir is {
    MoveUp -> Position { x: pos.x, y: pos.y + 1 }
    MoveDown -> Position { x: pos.x, y: pos.y - 1 }
    MoveLeft -> Position { x: pos.x - 1, y: pos.y }
    MoveRight -> Position { x: pos.x + 1, y: pos.y }
  }
}

fn in_bounds(pos: Position, level: Int) -> Bool {
  let max_coord = level * 10
  and {
    pos.x >= 0,
    pos.x < max_coord,
    pos.y >= 0,
    pos.y < max_coord,
  }
}

validator game_validator {
  spend(
    datum: Option<Data>,
    redeemer: GameRedeemer,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    let GameRedeemer { game_state_ref, direction, points_earned } = redeemer
    expect Some(ref_in) =
      transaction.find_input(self.reference_inputs, game_state_ref)
    expect InlineDatum(raw_game) = ref_in.output.datum
    expect game: GameState = raw_game
    let new_position = apply_move(game.position, direction)
    let position_valid = in_bounds(new_position, game.level)
    let is_player =
      list.has(self.extra_signatories, game.player)
    expect Some(own_datum_raw) = datum
    expect new_game: GameState = own_datum_raw
    and {
      is_player,
      position_valid,
      points_earned >= 0,
      new_game.position == new_position,
      new_game.score == game.score + points_earned,
      new_game.level == game.level,
      new_game.player == game.player,
    }
  }
}

