  Derecha
}

pub type RedeemerMovimiento {
  ref_estado_juego: OutputReference,
  direccion: Direccion,
  puntos_ganados: Int,
}

fn aplicar_movimiento(pos: Posicion, dir: Direccion) -> Posicion {
  when dir is {
    Arriba -> Posicion { x: pos.x, y: pos.y + 1 }
    Abajo -> Posicion { x: pos.x, y: pos.y - 1 }
    Izquierda -> Posicion { x: pos.x - 1, y: pos.y }
    Derecha -> Posicion { x: pos.x + 1, y: pos.y }
  }
}

fn dentro_de_limites(pos: Posicion, nivel: Int) -> Bool {
  let max_coord = nivel * 10
  and {
    pos.x >= 0,
    pos.x < max_coord,
    pos.y >= 0,
    pos.y < max_coord,
  }
}

validator validador_juego {
  spend(
    datum: Option<Data>,
    redeemer: RedeemerMovimiento,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    let RedeemerMovimiento { ref_estado_juego, direccion, puntos_ganados } = redeemer
    expect Some(ref_in) =
      transaction.find_input(self.reference_inputs, ref_estado_juego)
    expect InlineDatum(raw) = ref_in.output.datum
    expect estado: EstadoJuego = raw
    let nueva_posicion = aplicar_movimiento(estado.posicion, direccion)
    let posicion_valida = dentro_de_limites(nueva_posicion, estado.nivel)
    let es_jugador =
      list.has(self.extra_signatories, estado.jugador)
    expect Some(datum_propio_raw) = datum
    expect nuevo_estado: EstadoJuego = datum_propio_raw
    and {
      es_jugador,
      posicion_valida,
      puntos_ganados >= 0,
      nuevo_estado.posicion == nueva_posicion,
      nuevo_estado.puntuacion == estado.puntuacion + puntos_ganados,
      nuevo_estado.nivel == estado.nivel,
      nuevo_estado.jugador == estado.jugador,
    }
  }
}

