pub type AuctionState {
  seller: ByteArray,
  highest_bidder: Option<ByteArray>,
  highest_bid: Int,
  lot_name: ByteArray,
  deadline: Int,
  minimum_increment: Int,
}

pub type BidRedeemer {
  auction_ref: OutputReference,
  bid_amount: Int,
}

validator auction_bidder {
  spend(
    _datum: Option<Data>,
    redeemer: BidRedeemer,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    let BidRedeemer { auction_ref, bid_amount } = redeemer
    expect Some(ref_in) =
      transaction.find_input(self.reference_inputs, auction_ref)
    expect InlineDatum(raw_auction) = ref_in.output.datum
    expect auction: AuctionState = raw_auction
    let bid_exceeds_highest =
      bid_amount >= auction.highest_bid + auction.minimum_increment
    let seller_output_exists =
      list.any(
        self.outputs,
        fn(output) {
          when output.address.payment_credential is {
            VerificationKey(hash) ->
              hash == auction.seller && assets.lovelace_of(output.value) >= bid_amount
            _ -> False
          }
        },
      )
    let before_deadline =
      when self.validity_range.upper_bound.bound_type is {
        interval.Finite(upper_time) -> upper_time <= auction.deadline
        _ -> False
      }
    let refund_previous_bidder =
      when auction.highest_bidder is {
        None -> True
        Some(prev_bidder) ->
          list.any(
            self.outputs,
            fn(output) {
              when output.address.payment_credential is {
                VerificationKey(hash) ->
                  hash == prev_bidder && assets.lovelace_of(output.value) >= auction.highest_bid
                _ -> False
              }
            },
          )
      }
    and {
      bid_exceeds_highest,
      seller_output_exists,
      before_deadline,
      refund_previous_bidder,
    }
  }
}

