pub type EstadoSubasta {
  vendedor: ByteArray,
  mejor_postor: Option<ByteArray>,
  oferta_mas_alta: Int,
  nombre_lote: ByteArray,
  fecha_limite: Int,
  incremento_minimo: Int,
}

pub type RedeemerOferta {
  ref_subasta: OutputReference,
  monto_oferta: Int,
}

validator subasta {
  spend(
    _datum: Option<Data>,
    redeemer: RedeemerOferta,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    let RedeemerOferta { ref_subasta, monto_oferta } = redeemer
    expect Some(ref_in) =
      transaction.find_input(self.reference_inputs, ref_subasta)
    expect InlineDatum(raw) = ref_in.output.datum
    expect estado: EstadoSubasta = raw
    let oferta_supera_maxima =
      monto_oferta >= estado.oferta_mas_alta + estado.incremento_minimo
    let pago_al_vendedor =
      list.any(
        self.outputs,
        fn(salida) {
          when salida.address.payment_credential is {
            VerificationKey(hash) ->
              hash == estado.vendedor && assets.lovelace_of(salida.value) >= monto_oferta
            _ -> False
          }
        },
      )
    let antes_de_limite =
      when self.validity_range.upper_bound.bound_type is {
        interval.Finite(tiempo_superior) -> tiempo_superior <= estado.fecha_limite
        _ -> False
      }
    let reembolso_postor_anterior =
      when estado.mejor_postor is {
        None -> True
        Some(postor_previo) ->
          list.any(
            self.outputs,
            fn(salida) {
              when salida.address.payment_credential is {
                VerificationKey(hash) ->
                  hash == postor_previo && assets.lovelace_of(salida.value) >= estado.oferta_mas_alta
                _ -> False
              }
            },
          )
      }
    and {
      oferta_supera_maxima,
      pago_al_vendedor,
      antes_de_limite,
      reembolso_postor_anterior,
    }
  }
}

