type ProposalDatum {
  proposal_id: Int,
  description: ByteArray,
  vote_start: Int,
  vote_end: Int,
  yes_votes: Int,
  no_votes: Int,
}

type VoteDatum {
  proposal_id: Int,
  voter: ByteArray,
}

type VoteRedeemer {
  proposal_ref: OutputReference,
  vote_choice: Bool,
}

validator dao_voting {
  spend(
    datum: Option<VoteDatum>,
    redeemer: VoteRedeemer,
    own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(vote_datum) = datum

    // Read proposal from reference input
    expect Some(ref_in) =
      transaction.find_input(self.reference_inputs, redeemer.proposal_ref)

    expect InlineDatum(raw_proposal) = ref_in.output.datum
    expect proposal: ProposalDatum = raw_proposal

    // Validate the vote matches the proposal
    let ids_match = vote_datum.proposal_id == proposal.proposal_id

    // Check voter signed the transaction
    let voter_signed =
      list.has(self.extra_signatories, vote_datum.voter)

    // Check the vote is within the voting window
    let after_start =
      when self.validity_range.lower_bound.bound_type is {
        interval.Finite(lower_time) -> lower_time >= proposal.vote_start
        _ -> False
      }

    let before_end =
      when self.validity_range.upper_bound.bound_type is {
        interval.Finite(upper_time) -> upper_time <= proposal.vote_end
        _ -> False
      }

    ids_match && voter_signed && after_start && before_end
  }
}

