validator community_fund {
  spend(
    datum: Option<FundDatum>,
    redeemer: DisburseRedeemer,
    own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(_fund_datum) = datum

    // Read governance config from reference input
    expect Some(ref_in) =
      transaction.find_input(self.reference_inputs, redeemer.governance_ref)

    expect InlineDatum(raw_gov) = ref_in.output.datum
    expect gov: GovernanceDatum = raw_gov

    // Verify the governance reference is authenticated by admin policy NFT
    let gov_authenticated =
      assets.has_any_nft(ref_in.output.value, gov.admin_policy)

    // Check recipient is in the approved list
    let recipient_approved =
      list.has(gov.approved_recipients, redeemer.recipient)

