    let within_limit = redeemer.amount <= gov.max_per_recipient && redeemer.amount > 0

    // Verify there is an output paying the recipient
    let pays_recipient =
      list.any(
        self.outputs,
        fn(output) {
          when output.address.payment_credential is {
            cardano/address.VerificationKey(hash) ->
              hash == redeemer.recipient && assets.lovelace_of(output.value) >= redeemer.amount
            _ -> False
          }
        },
      )

    gov_authenticated && recipient_approved && within_limit && pays_recipient
  }
}

