type CompanionConfig {
  companion_script_hash: ByteArray,
}

type ForwardRedeemer {
  config_ref: OutputReference,
  forward_amount: Int,
}

validator forward_to_companion {
  spend(
    _datum: Option<Data>,
    redeemer: ForwardRedeemer,
    own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    let config_ref = redeemer.config_ref
    let forward_amount = redeemer.forward_amount
    expect Some(ref_input) =
      transaction.find_input(self.reference_inputs, config_ref)
    expect InlineDatum(raw_config) = ref_input.output.datum
    expect config: CompanionConfig = raw_config
    let companion_hash = config.companion_script_hash
    let companion_credential = Script(companion_hash)
    let outputs_to_companion =
      list.filter(
        self.outputs,
        fn(output) { output.address.payment_credential == companion_credential },
      )
    let total_sent =
      list.foldl(
        outputs_to_companion,
        0,
        fn(output, acc) { acc + assets.lovelace_of(output.value) },
      )
    expect Some(own_input) = transaction.find_input(self.inputs, own_ref)
    let own_lovelace = assets.lovelace_of(own_input.output.value)
    and {
      total_sent >= forward_amount,
      forward_amount > 0,
      own_lovelace >= forward_amount,
    }
  }
}

