  ) -> Bool {
    expect Some(whitelist_input) =
      transaction.find_input(self.reference_inputs, redeemer.whitelist_ref)
    expect InlineDatum(raw_whitelist) = whitelist_input.output.datum
    expect whitelist: OracleWhitelist = raw_whitelist
    expect Some(oracle_input) =
      transaction.find_input(self.reference_inputs, redeemer.oracle_ref)
    expect InlineDatum(raw_oracle) = oracle_input.output.datum
    expect oracle_data: OracleData = raw_oracle
    let oracle_cred = oracle_input.output.address.payment_credential
    expect Some(oracle_hash) = extract_script_hash(oracle_cred)
    let oracle_trusted =
      list.has(whitelist.trusted_oracles, oracle_hash)
    let price_acceptable = oracle_data.price >= redeemer.min_price
    and {
      oracle_trusted,
      price_acceptable,
    }
  }
}

