use cardano/transaction.{Transaction, OutputReference, Input, Output, InlineDatum, find_input}
use cardano/assets
use cardano/address.{Address, Credential, Script}
use aiken/collection/list
use aiken/collection/pairs

type ChainMapping {
  chain_id: Int,
  valid_destinations: List<ByteArray>,
  bridge_fee_lovelace: Int,
  bridge_operator: ByteArray,
}

type BridgeDatum {
  locked_amount: Int,
  sender: ByteArray,
}

type BridgeRedeemer {
  mapping_ref: OutputReference,
  target_chain_id: Int,
  destination_address: ByteArray,
}

validator cross_chain_bridge {
  spend(
    datum: Option<BridgeDatum>,
    redeemer: BridgeRedeemer,
    own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(bridge_datum) = datum
    expect Some(mapping_input) =
      transaction.find_input(self.reference_inputs, redeemer.mapping_ref)
    expect InlineDatum(raw_mapping) = mapping_input.output.datum
    expect mapping: ChainMapping = raw_mapping
    let chain_matches = redeemer.target_chain_id == mapping.chain_id
    let destination_valid =
      list.has(mapping.valid_destinations, redeemer.destination_address)
    let operator_signed =
      list.has(self.extra_signatories, mapping.bridge_operator)
    let sender_signed =
      list.has(self.extra_signatories, bridge_datum.sender)
    let fee_outputs =
      list.filter(
        self.outputs,
        fn(o) {
          o.address.payment_credential == Script(mapping.bridge_operator)
        },
      )
    let fee_paid =
      list.foldl(
        fee_outputs,
        0,
        fn(o, acc) { acc + assets.lovelace_of(o.value) },
      ) >= mapping.bridge_fee_lovelace
    and {
      chain_matches,
      destination_valid,
      or {
        operator_signed,
        sender_signed,
      },
      fee_paid,
    }
  }
}

use cardano/transaction.{Transaction, OutputReference, Input, Output, InlineDatum, find_input}
use cardano/assets
use cardano/address.{Credential, Script}
use aiken/collection/list

type PriceOracle {
  ada_usd_price: Int,
  decimals: Int,
  last_updated: Int,
}

type ProtocolConfig {
  min_collateral_ratio: Int,
  liquidation_threshold: Int,
  treasury_script_hash: ByteArray,
  max_loan_amount: Int,
}

type VaultDatum {
  owner: ByteArray,
  collateral_lovelace: Int,
  debt_usd: Int,
}

type VaultRedeemer {
  oracle_ref: OutputReference,
  config_ref: OutputReference,
  action: VaultAction,
}

type VaultAction {
  Borrow { amount_usd: Int }
  Repay { amount_usd: Int }
  Liquidate
}

validator defi_vault {
  spend(
    datum: Option<VaultDatum>,
    redeemer: VaultRedeemer,
    own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(vault) = datum
    expect Some(oracle_input) =
      transaction.find_input(self.reference_inputs, redeemer.oracle_ref)
    expect InlineDatum(raw_oracle) = oracle_input.output.datum
    expect oracle: PriceOracle = raw_oracle
    expect Some(config_input) =
      transaction.find_input(self.reference_inputs, redeemer.config_ref)
    expect InlineDatum(raw_config) = config_input.output.datum
    expect config: ProtocolConfig = raw_config
    let collateral_value_usd =
      vault.collateral_lovelace * oracle.ada_usd_price / 1000000
    when redeemer.action is {
      Borrow(amount_usd) -> {
        let new_debt = vault.debt_usd + amount_usd
        let ratio_ok =
          collateral_value_usd * 100 >= new_debt * config.min_collateral_ratio
        let under_max = new_debt <= config.max_loan_amount
        let owner_signed = list.has(self.extra_signatories, vault.owner)
        and {
          ratio_ok,
          under_max,
          owner_signed,
          amount_usd > 0,
        }
      }
      Repay(amount_usd) -> {
        let owner_signed = list.has(self.extra_signatories, vault.owner)
        and {
          owner_signed,
          amount_usd > 0,
          amount_usd <= vault.debt_usd,
        }
      }
      Liquidate -> {
        let undercollateralized =
          collateral_value_usd * 100 < vault.debt_usd * config.liquidation_threshold
        let treasury_cred = Script(config.treasury_script_hash)
        let treasury_outputs =
          list.filter(
            self.outputs,
            fn(o) { o.address.payment_credential == treasury_cred },
          )
        let treasury_receives =
          list.foldl(
            treasury_outputs,
            0,
            fn(o, acc) { acc + assets.lovelace_of(o.value) },
          )
        and {
          undercollateralized,
          treasury_receives >= vault.collateral_lovelace,
        }
      }
    }
  }
}

use cardano/transaction.{Transaction, OutputReference, Input, Output, InlineDatum, find_input}
use cardano/assets
use cardano/address.{Credential, Script}
use aiken/collection/list

type OraclePrecios {
  precio_ada_usd: Int,
  decimales: Int,
  ultima_actualizacion: Int,
}

type ConfigProtocolo {
  ratio_colateral_minimo: Int,
  umbral_liquidacion: Int,
  hash_tesoreria: ByteArray,
  prestamo_maximo: Int,
}

type DatumBoveda {
  propietario: ByteArray,
  colateral_lovelace: Int,
  deuda_usd: Int,
}

type AccionBoveda {
  Prestar { monto_usd: Int }
  Pagar { monto_usd: Int }
  Liquidar
}

type RedeemerBoveda {
  ref_oracle: OutputReference,
  ref_config: OutputReference,
  accion: AccionBoveda,
}

validator boveda_defi {
  spend(
    datum: Option<DatumBoveda>,
    redeemer: RedeemerBoveda,
    own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(boveda) = datum
    expect Some(entrada_oracle) =
      transaction.find_input(self.reference_inputs, redeemer.ref_oracle)
    expect InlineDatum(raw_oracle) = entrada_oracle.output.datum
    expect oracle: OraclePrecios = raw_oracle
    expect Some(entrada_config) =
      transaction.find_input(self.reference_inputs, redeemer.ref_config)
    expect InlineDatum(raw_config) = entrada_config.output.datum
    expect config: ConfigProtocolo = raw_config
    let valor_colateral_usd =
      boveda.colateral_lovelace * oracle.precio_ada_usd / 1000000
    when redeemer.accion is {
      Prestar(monto_usd) -> {
        let nueva_deuda = boveda.deuda_usd + monto_usd
        let ratio_ok =
          valor_colateral_usd * 100 >= nueva_deuda * config.ratio_colateral_minimo
        let bajo_maximo = nueva_deuda <= config.prestamo_maximo
        let firmado = list.has(self.extra_signatories, boveda.propietario)
        and {
          ratio_ok,
          bajo_maximo,
          firmado,
          monto_usd > 0,
        }
      }
      Pagar(monto_usd) -> {
        let firmado = list.has(self.extra_signatories, boveda.propietario)
        and {
          firmado,
          monto_usd > 0,
          monto_usd <= boveda.deuda_usd,
        }
      }
      Liquidar -> {
        let subcolateralizado =
          valor_colateral_usd * 100 < boveda.deuda_usd * config.umbral_liquidacion
        let cred_tesoreria = Script(config.hash_tesoreria)
        let salidas_tesoreria =
          list.filter(
            self.outputs,
            fn(s) { s.address.payment_credential == cred_tesoreria },
          )
        let total_tesoreria =
          list.foldl(
            salidas_tesoreria,
            0,
            fn(s, acc) { acc + assets.lovelace_of(s.value) },
          )
        and {
          subcolateralizado,
          total_tesoreria >= boveda.colateral_lovelace,
        }
      }
    }
  }
}

