use cardano/transaction.{Transaction, OutputReference, Input, find_input, InlineDatum}
use cardano/assets
use aiken/collection/list
use aiken/interval

type RateLimitConfig {
  max_withdrawals_per_epoch: Int,
  epoch_duration_ms: Int,
  config_nft_policy: ByteArray,
  config_nft_name: ByteArray,
}

type SpendDatum {
  owner: ByteArray,
  withdrawal_count: Int,
  epoch_start: Int,
}

type SpendRedeemer {
  Withdraw
  ResetEpoch
}

validator rate_limited_vault {
  spend(
    datum: Option<SpendDatum>,
    redeemer: SpendRedeemer,
    own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(d) = datum

    let config_ref_input: Option<Input> =
      list.find(
        self.reference_inputs,
        fn(ri) {
          assets.has_nft(ri.output.value, d.owner, "")
            |> fn(_) {
                 when ri.output.datum is {
                   InlineDatum(_) -> True
                   _ -> False
                 }
               }
        },
      )

    let find_config = fn() -> RateLimitConfig {
      let ref_with_config =
        list.find(
          self.reference_inputs,
          fn(ri) {
            when ri.output.datum is {
              InlineDatum(_raw) -> {
                let has_token =
                  assets.quantity_of(ri.output.value, #"aabb", #"636f6e666967") > 0
                has_token
              }
              _ -> False
            }
          },
        )
      expect Some(found) = ref_with_config
      when found.output.datum is {
        InlineDatum(raw) -> {
          expect config: RateLimitConfig = raw
          config
        }
        _ -> fail @"no inline datum on config ref"
      }
    }

    let config = find_config()

    expect Finite(tx_lower) = self.validity_range.lower_bound.bound_type

    let owner_signed =
      list.has(self.extra_signatories, d.owner)

    when redeemer is {
      Withdraw -> {
        let current_epoch_valid =
          tx_lower >= d.epoch_start && tx_lower < d.epoch_start + config.epoch_duration_ms
        let within_limit =
          d.withdrawal_count + 1 <= config.max_withdrawals_per_epoch
        let continuing_output =
          list.find(
            self.outputs,
            fn(o) {
              when o.datum is {
                InlineDatum(raw2) -> {
                  expect new_d: SpendDatum = raw2
                  new_d.owner == d.owner && new_d.withdrawal_count == d.withdrawal_count + 1 && new_d.epoch_start == d.epoch_start
                }
                _ -> False
              }
            },
          )
        owner_signed && current_epoch_valid && within_limit && when continuing_output is {
          Some(_) -> True
          None -> False
        }
      }
      ResetEpoch -> {
        let new_epoch_started = tx_lower >= d.epoch_start + config.epoch_duration_ms
        let continuing_output =
          list.find(
            self.outputs,
            fn(o) {
              when o.datum is {
                InlineDatum(raw2) -> {
                  expect new_d: SpendDatum = raw2
                  new_d.owner == d.owner && new_d.withdrawal_count == 0 && new_d.epoch_start == tx_lower
                }
                _ -> False
              }
            },
          )
        owner_signed && new_epoch_started && when continuing_output is {
          Some(_) -> True
          None -> False
        }
      }
    }
  }
}

use cardano/transaction.{Transaction, OutputReference, Input, find_input, InlineDatum}
use cardano/assets
use aiken/collection/list

type ConfigLimite {
  max_retiros_por_epoca: Int,
  duracion_epoca_ms: Int,
  nft_config_policy: ByteArray,
  nft_config_nombre: ByteArray,
}

type DatoBoveda {
  dueno: ByteArray,
  conteo_retiros: Int,
  inicio_epoca: Int,
}

validator boveda_con_limite {
  spend(
    datum: Option<DatoBoveda>,
    _redeemer: Data,
    own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(d) = datum

    // Buscar referencia con configuración de límite
    let ref_config =
      list.find(
        self.reference_inputs,
        fn(ri) {
          assets.has_nft(ri.output.value, #"ccdd", #"6c696d697465")
        },
      )
    expect Some(encontrada) = ref_config

    expect InlineDatum(raw_config) = encontrada.output.datum
    expect config: ConfigLimite = raw_config

    // Extraer tiempo inferior de validez
    expect Finite(tiempo_inferior) = self.validity_range.lower_bound.bound_type

    let firmado_por_dueno =
      list.has(self.extra_signatories, d.dueno)

    // Verificar que estamos dentro de la época actual
    let dentro_de_epoca =
      tiempo_inferior >= d.inicio_epoca && tiempo_inferior < d.inicio_epoca + config.duracion_epoca_ms

    // Verificar que no se excede el límite
    let dentro_de_limite =
      d.conteo_retiros + 1 <= config.max_retiros_por_epoca

    // Verificar salida continuante con conteo actualizado
    let salida_valida =
      list.any(
        self.outputs,
        fn(o) {
          when o.datum is {
            InlineDatum(raw_nuevo) -> {
              expect nuevo: DatoBoveda = raw_nuevo
              nuevo.dueno == d.dueno && nuevo.conteo_retiros == d.conteo_retiros + 1 && nuevo.inicio_epoca == d.inicio_epoca
            }
            _ -> False
          }
        },
      )

    firmado_por_dueno && dentro_de_epoca && dentro_de_limite && salida_valida
  }
}

use cardano/transaction.{Transaction, OutputReference, Input, find_input, InlineDatum}
use cardano/assets
use aiken/collection/list

type FaucetConfig {
  drip_amount_lovelace: Int,
  cooldown_ms: Int,
  faucet_nft_policy: ByteArray,
  faucet_nft_name: ByteArray,
}

type FaucetState {
  last_claim_time: Int,
}

validator drip_faucet {
  spend(
    datum: Option<FaucetState>,
    _redeemer: Data,
    own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(state) = datum

    // Read faucet config from reference input
    let config_ref =
      list.find(
        self.reference_inputs,
        fn(ri) {
          assets.has_nft(ri.output.value, #"face7c0ff1g", #"64726970636667")
        },
      )
    expect Some(config_input) = config_ref
    expect InlineDatum(raw_config) = config_input.output.datum
    expect config: FaucetConfig = raw_config

    // Get current time from validity range lower bound
    expect Finite(now) = self.validity_range.lower_bound.bound_type

    // Enforce cooldown: enough time must have passed since last claim
    let time_since_last = now - state.last_claim_time
    let cooldown_met = time_since_last >= config.cooldown_ms

    // Find own input to determine script address
    let own_input = transaction.resolve_input(self.inputs, own_ref)
    let script_address = own_input.address

    // Find continuing output back to the faucet
    let continuing_output =
      list.find(
        self.outputs,
        fn(o) {
          o.address == script_address
        },
      )
    expect Some(cont_out) = continuing_output

    // Verify updated state in continuing output
    expect InlineDatum(raw_new_state) = cont_out.datum
    expect new_state: FaucetState = raw_new_state
    let state_updated = new_state.last_claim_time == now

    // Verify faucet only dispenses the configured drip amount
    let input_lovelace = assets.lovelace_of(own_input.value)
    let output_lovelace = assets.lovelace_of(cont_out.value)
    let dispensed = input_lovelace - output_lovelace
    let correct_drip = dispensed <= config.drip_amount_lovelace && dispensed > 0

    cooldown_met && state_updated && correct_drip
  }
}

use cardano/transaction.{Transaction, OutputReference, Input, find_input, InlineDatum}
use cardano/assets
use aiken/collection/list

type ConfigGoteo {
  cantidad_goteo: Int,
  enfriamiento_ms: Int,
}

type EstadoFaucet {
  ultimo_reclamo: Int,
}

validator faucet_goteo {
  spend(
    datum: Option<EstadoFaucet>,
    _redeemer: Data,
    own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(estado) = datum

    // Leer configuración desde entrada de referencia
    let ref_encontrada =
      list.find(
        self.reference_inputs,
        fn(ri) {
          assets.has_nft(ri.output.value, #"aabbcc01", #"676f74656f")
        },
      )
    expect Some(entrada_config) = ref_encontrada
    expect InlineDatum(raw_cfg) = entrada_config.output.datum
    expect cfg: ConfigGoteo = raw_cfg

    // Obtener tiempo actual del rango de validez
    expect Finite(ahora) = self.validity_range.lower_bound.bound_type

    // Verificar que ha pasado suficiente tiempo
    let tiempo_transcurrido = ahora - estado.ultimo_reclamo
    let enfriamiento_cumplido = tiempo_transcurrido >= cfg.enfriamiento_ms

    // Obtener entrada propia
    let entrada_propia = transaction.resolve_input(self.inputs, own_ref)
    let direccion_script = entrada_propia.address

    // Buscar salida continuante
    let salida_cont =
      list.find(
        self.outputs,
        fn(o) { o.address == direccion_script },
      )
    expect Some(salida) = salida_cont

    // Verificar estado actualizado
    expect InlineDatum(raw_nuevo) = salida.datum
    expect nuevo_estado: EstadoFaucet = raw_nuevo
    let estado_actualizado = nuevo_estado.ultimo_reclamo == ahora

    // Verificar cantidad dispensada
    let lovelace_entrada = assets.lovelace_of(entrada_propia.value)
    let lovelace_salida = assets.lovelace_of(salida.value)
    let dispensado = lovelace_entrada - lovelace_salida
    let goteo_correcto = dispensado <= cfg.cantidad_goteo && dispensado > 0

    enfriamiento_cumplido && estado_actualizado && goteo_correcto
  }
}

use cardano/transaction.{Transaction, OutputReference, Input, find_input, InlineDatum}
use cardano/assets
use aiken/collection/list

type OracleMultiplier {
  multiplier_numerator: Int,
  multiplier_denominator: Int,
  valid_after: Int,
  valid_before: Int,
  oracle_nft_policy: ByteArray,
  oracle_nft_name: ByteArray,
}

type PayoutDatum {
  beneficiary: ByteArray,
  base_amount_lovelace: Int,
  oracle_ref: OutputReference,
}

validator multiplied_payout {
  spend(
    datum: Option<PayoutDatum>,
    _redeemer: Data,
    own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(d) = datum

    // Find oracle reference input by stored output reference
    expect Some(oracle_input) =
      transaction.find_input(self.reference_inputs, d.oracle_ref)

    // Extract oracle multiplier data
    expect InlineDatum(raw_oracle) = oracle_input.output.datum
    expect oracle: OracleMultiplier = raw_oracle

    // Verify oracle has authentic NFT
    let oracle_authentic =
      assets.has_nft(
        oracle_input.output.value,
        oracle.oracle_nft_policy,
        oracle.oracle_nft_name,
      )

    // Get current time from validity range
    expect Finite(tx_lower) = self.validity_range.lower_bound.bound_type
    expect Finite(tx_upper) = self.validity_range.upper_bound.bound_type

    // Ensure transaction time falls within oracle validity window
    let oracle_time_valid =
      tx_lower >= oracle.valid_after && tx_upper <= oracle.valid_before

    // Compute final payout: base_amount * (numerator / denominator)
    let final_payout =
      d.base_amount_lovelace * oracle.multiplier_numerator / oracle.multiplier_denominator

    // Beneficiary must sign
    let beneficiary_signed =
      list.has(self.extra_signatories, d.beneficiary)

    // Verify beneficiary receives at least the computed payout
    let beneficiary_paid =
      list.any(
        self.outputs,
        fn(o) {
          when o.address.payment_credential is {
            VerificationKey(hash) ->
              hash == d.beneficiary && assets.lovelace_of(o.value) >= final_payout
            _ -> False
          }
        },
      )

    oracle_authentic && oracle_time_valid && beneficiary_signed && beneficiary_paid
  }
}

use cardano/transaction.{Transaction, OutputReference, Input, find_input, InlineDatum}
use cardano/assets
use aiken/collection/list

type MultiplicadorOracle {
  numerador: Int,
  denominador: Int,
  valido_desde: Int,
  valido_hasta: Int,
}

type DatoPago {
  beneficiario: ByteArray,
  monto_base: Int,
  ref_oracle: OutputReference,
  nft_oracle_policy: ByteArray,
  nft_oracle_nombre: ByteArray,
}

validator pago_con_multiplicador {
  spend(
    datum: Option<DatoPago>,
    _redeemer: Data,
    own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(d) = datum

    // Encontrar entrada de referencia del oráculo
    expect Some(entrada_oracle) =
      transaction.find_input(self.reference_inputs, d.ref_oracle)

    // Verificar autenticidad del oráculo con NFT
    let oracle_autentico =
      assets.has_nft(
        entrada_oracle.output.value,
        d.nft_oracle_policy,
        d.nft_oracle_nombre,
      )

    // Extraer datos del multiplicador
    expect InlineDatum(raw_mult) = entrada_oracle.output.datum
    expect mult: MultiplicadorOracle = raw_mult

    // Validar que el tiempo de la transacción está dentro de la ventana del oráculo
    expect Finite(t_inferior) = self.validity_range.lower_bound.bound_type
    expect Finite(t_superior) = self.validity_range.upper_bound.bound_type
    let tiempo_valido =
      t_inferior >= mult.valido_desde && t_superior <= mult.valido_hasta

    // Calcular pago final con multiplicador
    let pago_final = d.monto_base * mult.numerador / mult.denominador

    // El beneficiario debe firmar
    let firmado =
      list.has(self.extra_signatories, d.beneficiario)

    // Verificar que el beneficiario recibe el pago calculado
    let beneficiario_pagado =
      list.any(
        self.outputs,
        fn(o) {
          when o.address.payment_credential is {
            VerificationKey(hash) ->
              hash == d.beneficiario && assets.lovelace_of(o.value) >= pago_final
            _ -> False
          }
        },
      )

    oracle_autentico && tiempo_valido && firmado && beneficiario_pagado
  }
}

use cardano/transaction.{Transaction, OutputReference, Input, find_input, InlineDatum}
use cardano/assets
use aiken/collection/list

type VestingSchedule {
  start_time: Int,
  cliff_duration_ms: Int,
  total_vesting_duration_ms: Int,
  total_tokens: Int,
  token_policy: ByteArray,
  token_name: ByteArray,
}

type VestingDatum {
  beneficiary: ByteArray,
  tokens_claimed: Int,
  schedule_ref: OutputReference,
  schedule_nft_policy: ByteArray,
  schedule_nft_name: ByteArray,
}

validator vesting_contract {
  spend(
    datum: Option<VestingDatum>,
    _redeemer: Data,
    own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(d) = datum

    // Read vesting schedule from reference input
    expect Some(schedule_input) =
      transaction.find_input(self.reference_inputs, d.schedule_ref)

    let schedule_authentic =
      assets.has_nft(
        schedule_input.output.value,
        d.schedule_nft_policy,
        d.schedule_nft_name,
      )

    expect InlineDatum(raw_schedule) = schedule_input.output.datum
    expect schedule: VestingSchedule = raw_schedule

    // Get current time
    expect Finite(now) = self.validity_range.lower_bound.bound_type

    // Calculate elapsed time since vesting start
    let elapsed = now - schedule.start_time

    // Check cliff period has passed
    let past_cliff = elapsed >= schedule.cliff_duration_ms

    // Calculate unlocked tokens using linear vesting
    let unlocked =
      if elapsed >= schedule.total_vesting_duration_ms then
        schedule.total_tokens
      else
        schedule.total_tokens * elapsed / schedule.total_vesting_duration_ms

    // How many tokens can be claimed now
    let claimable = unlocked - d.tokens_claimed

    // Beneficiary must sign
    let beneficiary_signed =
      list.has(self.extra_signatories, d.beneficiary)

    // Find own input
    let own_input = transaction.resolve_input(self.inputs, own_ref)
    let script_address = own_input.address

    // Verify beneficiary receives claimed tokens
    let beneficiary_receives_tokens =
      list.any(
        self.outputs,
        fn(o) {
          when o.address.payment_credential is {
            VerificationKey(hash) ->
              hash == d.beneficiary && assets.quantity_of(
                o.value,
                schedule.token_policy,
                schedule.token_name,
              ) >= claimable
            _ -> False
          }
        },
      )

    // Verify continuing output with updated claim count (unless fully vested)
    let continuing_valid =
      if unlocked == schedule.total_tokens && d.tokens_claimed + claimable == schedule.total_tokens then
        True
      else
        list.any(
          self.outputs,
          fn(o) {
            if o.address == script_address then
              when o.datum is {
                InlineDatum(raw_new) -> {
                  expect new_d: VestingDatum = raw_new
                  new_d.beneficiary == d.beneficiary && new_d.tokens_claimed == d.tokens_claimed + claimable && new_d.schedule_ref == d.schedule_ref
                }
                _ -> False
              }
            else
              False
          },
        )

    schedule_authentic && past_cliff && claimable > 0 && beneficiary_signed && beneficiary_receives_tokens && continuing_valid
  }
}

use cardano/transaction.{Transaction, OutputReference, Input, find_input, InlineDatum}
use cardano/assets
use aiken/collection/list

type CalendarioVesting {
  tiempo_inicio: Int,
  duracion_cliff_ms: Int,
  duracion_total_ms: Int,
  total_tokens: Int,
  policy_token: ByteArray,
  nombre_token: ByteArray,
}

type DatoVesting {
  beneficiario: ByteArray,
  tokens_reclamados: Int,
  ref_calendario: OutputReference,
  nft_calendario_policy: ByteArray,
  nft_calendario_nombre: ByteArray,
}

validator contrato_vesting {
  spend(
    datum: Option<DatoVesting>,
    _redeemer: Data,
    own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(d) = datum

    // Leer calendario de vesting desde referencia
    expect Some(entrada_calendario) =
      transaction.find_input(self.reference_inputs, d.ref_calendario)

    let calendario_autentico =
      assets.has_nft(
        entrada_calendario.output.value,
        d.nft_calendario_policy,
        d.nft_calendario_nombre,
      )

    expect InlineDatum(raw_cal) = entrada_calendario.output.datum
    expect cal: CalendarioVesting = raw_cal

    // Obtener tiempo actual
    expect Finite(ahora) = self.validity_range.lower_bound.bound_type

    // Calcular tiempo transcurrido
    let transcurrido = ahora - cal.tiempo_inicio

    // Verificar que pasó el cliff
    let paso_cliff = transcurrido >= cal.duracion_cliff_ms

    // Calcular tokens desbloqueados linealmente
    let desbloqueados =
      if transcurrido >= cal.duracion_total_ms then
        cal.total_tokens
      else
        cal.total_tokens * transcurrido / cal.duracion_total_ms

    // Tokens reclamables ahora
    let reclamables = desbloqueados - d.tokens_reclamados

    // El beneficiario debe firmar
    let firmado =
      list.has(self.extra_signatories, d.beneficiario)

    // Obtener entrada propia
    let entrada_propia = transaction.resolve_input(self.inputs, own_ref)
    let dir_script = entrada_propia.address

    // Verificar que beneficiario recibe tokens
    let beneficiario_recibe =
      list.any(
        self.outputs,
        fn(o) {
          when o.address.payment_credential is {
            VerificationKey(hash) ->
              hash == d.beneficiario && assets.quantity_of(
                o.value,
                cal.policy_token,
                cal.nombre_token,
              ) >= reclamables
            _ -> False
          }
        },
      )

    // Verificar salida continuante con estado actualizado
    let continuacion_valida =
      if desbloqueados == cal.total_tokens && d.tokens_reclamados + reclamables == cal.total_tokens then
        True
      else
        list.any(
          self.outputs,
          fn(o) {
            if o.address == dir_script then
              when o.datum is {
                InlineDatum(raw_nuevo) -> {
                  expect nuevo: DatoVesting = raw_nuevo
                  nuevo.beneficiario == d.beneficiario && nuevo.tokens_reclamados == d.tokens_reclamados + reclamables && nuevo.ref_calendario == d.ref_calendario
                }
                _ -> False
              }
            else
              False
          },
        )

    calendario_autentico && paso_cliff && reclamables > 0 && firmado && beneficiario_recibe && continuacion_valida
  }
}
